{#
  Use the +schema config value verbatim (upper-cased) instead of dbt's default
  behaviour of prefixing it with target.schema. Without this, a model configured
  with +schema: analytics_stg would land in "ANALYTICS_analytics_stg". We want the
  two clean lineage schemas — ANALYTICS_STG (staging views) and ANALYTICS (marts) —
  so the on-run-end reader grants and #611/#596 lineage ingestion have stable names.
#}
{% macro generate_schema_name(custom_schema_name, node) -%}
    {%- if custom_schema_name is none -%}
        {{ target.schema | trim | upper }}
    {%- else -%}
        {{ custom_schema_name | trim | upper }}
    {%- endif -%}
{%- endmacro %}

