1	import { Form, Input, Select, type FormInstance } from 'antd';
2	
3	import type { ConnectionType } from '../../api/connections';
4	import { activeAuthOption, CONNECTION_FORM_SPECS, type TextField } from './connectionFormSpec';
5	
6	/**
7	 * Renders the type-specific config + secret form fields from CONNECTION_FORM_SPECS.
8	 * Config fields are namespaced under `config` (name={['config','account']}) so the
9	 * drawer submits `config` as one object; the write-only credential is `secret`.
10	 */
11	
12	const requiredRule = [{ required: true }];
13	
14	function ConfigTextField({
15	  field,
16	  forceRequired = false,
17	}: {
18	  field: TextField;
19	  forceRequired?: boolean;
20	}) {
21	  const optional = field.optional && !forceRequired;
22	  return (
23	    <Form.Item
24	      name={['config', field.name]}
25	      label={optional ? `${field.label} (optional)` : field.label}
26	      rules={optional ? undefined : requiredRule}
27	    >
28	      <Input />
29	    </Form.Item>
30	  );
31	}
32	
33	/** The write-only credential input — shared by the create form and ReauthModal. */
34	export function SecretField({
35	  label,
36	  multiline = false,
37	  extra,
38	}: {
39	  label: string;
40	  multiline?: boolean;
41	  extra?: string;
42	}) {
43	  return (
44	    <Form.Item name="secret" label={label} rules={requiredRule} extra={extra}>
45	      {multiline ? (
46	        <Input.TextArea rows={4} autoComplete="off" />
47	      ) : (
48	        <Input.Password autoComplete="off" />
49	      )}
50	    </Form.Item>
51	  );
52	}
53	
54	/** Optional second secret part (e.g. key-pair passphrase) — rides `composeSecret`.
55	 * The form's `requiredMark="optional"` renders the (optional) marker.
56	 * `preserve={false}` drops the value when the field unmounts (auth-mode switch,
57	 * modal close) so a stale passphrase can never wrap another mode's secret. */
58	export function PassphraseField({ label }: { label: string }) {
59	  return (
60	    <Form.Item
61	      name="secretPassphrase"
62	      label={label}
63	      preserve={false}
64	      extra="Only for passphrase-protected keys; leave blank for an unencrypted key."
65	    >
66	      <Input.Password autoComplete="off" />
67	    </Form.Item>
68	  );
69	}
70	
71	export function ConnectionTypeFields({
72	  type,
73	  form,
74	  showSecret = true,
75	}: {
76	  type: ConnectionType;
77	  form: FormInstance;
78	  /** Edit mode omits the secret — credential rotation is the Re-auth flow. */
79	  showSecret?: boolean;
80	}) {
81	  const spec = CONNECTION_FORM_SPECS[type];
82	  const authType = Form.useWatch(['config', 'auth_type'], form) as string | undefined;
83	  const activeAuth = activeAuthOption(type, { auth_type: authType });
84	
85	  return (
86	    <>
87	      {spec.textFields.map((f) => (
88	        <ConfigTextField
89	          key={f.name}
90	          field={f}
91	          forceRequired={activeAuth?.requiredFields?.includes(f.name)}
92	        />
93	      ))}
94	
95	      {spec.auth && (
96	        <Form.Item name={['config', 'auth_type']} label="Auth type" rules={requiredRule}>
97	          <Select options={spec.auth.map((a) => ({ value: a.value, label: a.label }))} />
98	        </Form.Item>
99	      )}
100	
101	      {activeAuth?.extraField && <ConfigTextField field={activeAuth.extraField} />}
102	
103	      {showSecret &&
104	        (activeAuth ? (
105	          <>
106	            <SecretField label={activeAuth.secretLabel} multiline={activeAuth.multilineSecret} />
107	            {activeAuth.passphraseLabel && <PassphraseField label={activeAuth.passphraseLabel} />}
108	          </>
109	        ) : (
110	          spec.secretLabel && <SecretField label={spec.secretLabel} />
111	        ))}
112	    </>
113	  );
114	}
