2	
3	/**
4	 * Connections API — the six configurable connection types (CLAUDE.md §4).
5	 * ADF + Airflow are orchestration providers, not datasources, but they are
6	 * still `connections` rows and managed through the same CRUD surface.
7	 */
8	
9	export const CONNECTION_TYPES = [
10	  'snowflake',
11	  'adls_gen2',
12	  's3',
13	  'unity_catalog',
14	  'adf',
15	  'airflow',
16	] as const;
17	export type ConnectionType = (typeof CONNECTION_TYPES)[number];
18	
19	/**
20	 * Datasource vs orchestration is the load-bearing distinction in DataQ
21	 * (CLAUDE.md §4): datasources are stores you write checks against; ADF/Airflow
22	 * are orchestration providers we monitor + trigger from, never queryable. This
23	 * map is the single source for that split — the add-connection picker and the
24	 * sectioned list both derive their groups from it (no hardcoded lists elsewhere).
25	 */
26	export const CONNECTION_KINDS = ['datasource', 'orchestration'] as const;
27	export type ConnectionKind = (typeof CONNECTION_KINDS)[number];
28	
29	export const CONNECTION_KIND: Record<ConnectionType, ConnectionKind> = {
30	  snowflake: 'datasource',
31	  adls_gen2: 'datasource',
32	  s3: 'datasource',
33	  unity_catalog: 'datasource',
34	  adf: 'orchestration',
35	  airflow: 'orchestration',
36	};
37	
38	export const CONNECTION_KIND_LABELS: Record<ConnectionKind, string> = {
39	  datasource: 'Data sources',
40	  orchestration: 'Orchestration',
41	};
42	
43	/** Types of a given kind, in canonical CONNECTION_TYPES order. */
44	export const typesOfKind = (kind: ConnectionKind): ConnectionType[] =>
45	  CONNECTION_TYPES.filter((t) => CONNECTION_KIND[t] === kind);
46	
47	export const DATASOURCE_TYPES = typesOfKind('datasource');
48	export const ORCHESTRATION_TYPES = typesOfKind('orchestration');
49	
50	/**
51	 * Coarser datasource grouping for the Results datasource-type filter (ADR 0022):
52	 * the two flat-file types (ADLS Gen2 + S3) share a runner shape and read as one
53	 * "Flat file" choice, while Snowflake and Unity Catalog stand alone. Orchestration
54	 * types map to `null` — they're never queryable, so they never back a suite/run.
55	 */
56	export const DATASOURCE_CATEGORIES = ['snowflake', 'flatfile', 'unity_catalog'] as const;
57	export type DatasourceCategory = (typeof DATASOURCE_CATEGORIES)[number];
58	
59	export const DATASOURCE_CATEGORY: Record<ConnectionType, DatasourceCategory | null> = {
60	  snowflake: 'snowflake',
61	  adls_gen2: 'flatfile',
62	  s3: 'flatfile',
63	  unity_catalog: 'unity_catalog',
64	  adf: null,
65	  airflow: null,
66	};
67	
68	export const DATASOURCE_CATEGORY_LABELS: Record<DatasourceCategory, string> = {
69	  snowflake: 'Snowflake',
70	  flatfile: 'Flat file',
71	  unity_catalog: 'Unity Catalog',
72	};
73	
74	/**
75	 * Datasources GX can run a custom-SQL (`UnexpectedRowsExpectation`) query against
76	 * — mirrors the backend `custom_sql.SQL_QUERYABLE_TYPES` (ADR 0019). The custom-SQL
77	 * check category is offered only for these SQL-queryable types; flat files (ADLS /
78	 * S3) are DataFrame assets, not SQL, and the backend 422s custom-SQL on any other.
79	 */
80	export const SQL_QUERYABLE_TYPES: ConnectionType[] = ['snowflake', 'unity_catalog'];
81	
82	export const isSqlQueryable = (type: ConnectionType): boolean => SQL_QUERYABLE_TYPES.includes(type);
83	
84	export const CONNECTION_ENVS = ['dev', 'qa', 'uat', 'prod'] as const;
85	export type ConnectionEnv = (typeof CONNECTION_ENVS)[number];
86	
87	/** Display label for an env (single source for the list page + the drawer). */
88	export const envLabel = (env: ConnectionEnv): string => env.toUpperCase();
89	
90	/** Tag color per env — shared by every page that renders an env badge. */
91	export const ENV_COLORS: Record<ConnectionEnv, string> = {
92	  dev: 'blue',
93	  qa: 'gold',
94	  uat: 'purple',
95	  prod: 'red',
96	};
97	
98	/** Mirrors the backend `ConnectionRead` schema (secret is never returned). */
99	export interface Connection {
100	  id: string;
101	  name: string;
102	  type: ConnectionType;
103	  env: ConnectionEnv;
104	  config: Record<string, unknown>;
105	  has_secret: boolean;
106	  created_by: string;
107	}
108	
109	/** Human-readable labels for the connection types, for grouping + display. */
110	export const CONNECTION_TYPE_LABELS: Record<ConnectionType, string> = {
111	  snowflake: 'Snowflake',
112	  adls_gen2: 'ADLS Gen2',
113	  s3: 'AWS S3',
114	  unity_catalog: 'Unity Catalog',
115	  adf: 'Azure Data Factory',
116	  airflow: 'Airflow',
117	};
118	
119	export async function listConnections(params?: {
120	  type?: ConnectionType;
121	  env?: ConnectionEnv;
122	}): Promise<Connection[]> {
123	  const { data } = await api.get<Connection[]>('/connections', { params });
124	  return data;
125	}
126	
127	/** Fetch one connection by id (e.g. to learn a suite's datasource type). */
128	export async function getConnection(id: string): Promise<Connection> {
129	  const { data } = await api.get<Connection>(`/connections/${id}`);
130	  return data;
131	}
132	
133	/** Live connectivity test — a green result means the credential authenticates. */
134	export async function testConnection(id: string): Promise<{ ok: boolean }> {
135	  const { data } = await api.post<{ ok: boolean }>(`/connections/${id}/test`);
136	  return data;
137	}
138	
139	/** Mirrors the backend `ConnectionCreate` schema (secret is write-only). */
140	export interface ConnectionCreate {
141	  name: string;
142	  type: ConnectionType;
143	  env: ConnectionEnv;
144	  config: Record<string, unknown>;
145	  secret?: string;
146	}
147	
148	export async function createConnection(payload: ConnectionCreate): Promise<Connection> {
149	  const { data } = await api.post<Connection>('/connections', payload);
150	  return data;
151	}
152	
153	/** Mirrors the backend `ConnectionUpdate` schema — type/env are immutable. */
154	export interface ConnectionUpdate {
155	  name?: string;
156	  config?: Record<string, unknown>;
157	  secret?: string;
158	}
159	
160	export async function updateConnection(id: string, payload: ConnectionUpdate): Promise<Connection> {
161	  const { data } = await api.patch<Connection>(`/connections/${id}`, payload);
162	  return data;
163	}
164	
165	export async function deleteConnection(id: string): Promise<void> {
166	  await api.delete(`/connections/${id}`);
167	}
168	
169	/** Rotate the credential and verify it in one step (bad credential → error). */
170	export async function reauthConnection(id: string, secret: string): Promise<{ ok: boolean }> {
171	  const { data } = await api.post<{ ok: boolean }>(`/connections/${id}/reauth`, { secret });
172	  return data;
173	}
